UPDATE public.email_templates SET body_template = '<p>{{civilite}} {{prenom}} {{nom}}<br>{{adresse}}<br>{{code_postal}} {{ville}}</p><p>📍 Lyon, le {{date_jour}}</p><p><strong>Objet : Convocation à la formation VTC</strong></p><p>{{civilite}} {{prenom}} {{nom}},</p><p>Nous avons le plaisir de vous confirmer votre inscription à la formation <strong>{{formation}}</strong>.</p><p>📅 Votre formation théorique se déroulera <strong>du lundi au vendredi, du {{date_debut}} au {{date_fin}}</strong> dans nos locaux situés au :<br>🏢 <strong>86 route de Genas, 69003 Lyon</strong><br>🕐 <strong>Horaires : 8h45 - 12h / 13h - 16h</strong></p><p><span style="background-color: yellow; padding: 2px 4px;">📝 Vous passerez votre examen théorique le {{date_examen_theorique}} sur Clermont Ferrand.</span></p><p>Il vous est aussi possible de faire votre formation pratique directement après la théorie.</p><p><span style="background-color: yellow; padding: 2px 4px;">🚗 En cas de réussite à l''examen théorique, vous devrez choisir une date d''entrainement pratique entre le 20 avril et le 1er mai 2026.</span></p><p><span style="background-color: yellow; padding: 2px 4px;">🎯 Vous passerez un examen pratique entre le 4 et le 8 mai 2026.</span></p><p>⚠️ Des travaux sont en cours à proximité de nos locaux. Nous vous conseillons de privilégier les transports en commun (Métro Guillotière ou Saxe-Gambetta).</p><p style="color: red; font-weight: bold;">⚠️ ATTENTION !!! Les examens sont organisés par la chambre des métiers et de l''artisanat, il peut avoir des changements ou des annulations, pour toutes questions concernant les examens ou les inscriptions, merci de bien vouloir les contacter au numéro suivant : 04.72.43.43.00. Attention en cas de report de la formation et ou de l''examen, des frais peuvent être appliqués.</p><p>Pour toute question, n''hésitez pas à nous contacter.</p><p>Cordialement,</p><p><strong>Ftransport</strong><br>📍 86 route de Genas, 69003 Lyon<br>📞 04.72.43.43.00<br>✉️ contact@ftransport.fr<br>SIRET : 82346156100018<br>N° de déclaration d''activité : 84 69 15114 69</p>' WHERE id = 'convocation-vtc';